OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page



   if(IsProject()==0)  

   {

      int global1=5;

      int global2=0;

      int global3=0;

      int global4=0;



      CString parentWnd;

   }

   parentWnd.SetString("rycerz1.bdf");



   int hitTable[7];

   int mOn=0;

   int move=0;



   if(global1<5)   global1=5;



   MultiBitmap.ShowBitmap(global1-5,0,0,1);   //numer rycerza-5

   MultiBitmap.ShowBitmap(global1-2,1,430,2);   //numer rycerza-5





   Panorama.OpenPanorama(0);



   LoadGroup("Cursors.grp");

   SetCursor(0);



   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   Sound_Holder.PlayDSound(1);

   FadeScreen(1,1000);

   SetTimer(3000);

}





