{

	// Add your close page handler code here



}







void Panorama.SpriteMouseMoveIn(int panoramaNo,int spriteNo)

{

   if(hitTable[spriteNo]==0)   

   {

      SetCursor(1);

      mOn=1;

   }

}





void Panorama.SpriteMouseMoveOut()

{

   mOn=0;

   SetCursor(0);

}







